package com.example.myapplication.data

import com.google.gson.annotations.SerializedName

data class RefinedExercise(
    val name: String,
    val description: String,
    val difficulty: Int,
    val category: String,
    val equipment: String,
    val notes: String?,
    @SerializedName("calories_per_kg_per_hour") val caloriesPerKgPerHour: Double,
    @SerializedName("primary_muscle") val primaryMuscle: String,
    @SerializedName("secondary_muscles") val secondaryMuscles: List<String>,
    @SerializedName("typical_sets_reps") val typicalSetsReps: String,
    @SerializedName("execution_tips") val executionTips: List<String>,
    @SerializedName("video_url") val videoUrl: String,

    // Pre-parsed execution parameters
    val parsedSets: Int = 3,
    val parsedReps: Int = 12,
    val repsDisplay: String = "12", // Original string preserving dashes, e.g., "10-12"
    val recommendedRestSeconds: Int = 60,

    // Muscle intensities are dynamic keys in JSON, so we might need custom deserialization
    // or just map them manually if using a library like Gson with a custom adapter.
    // simpler approach: load as Map<String, Any> first, then convert.
    // OR: just add the known ones as nullable fields if they are finite,
    // but the prompt implies dynamic "muscle_intensity_*" keys.
    // I'll use a custom deserializer or just parse the whole object as a Map for flexibility in the repository.
    val muscleIntensities: Map<String, MuscleIntensity> = emptyMap()
)

data class MuscleIntensity(
    val muscleName: String,
    val role: MuscleRole, // P, S, T
    val level: Int // 1-10
)

enum class MuscleRole {
    PRIMARY, SECONDARY, TERTIARY, NONE
}

package com.example.myapplication.data

import kotlinx.serialization.SerialName
import kotlinx.serialization.Serializable

@Serializable
data class RefinedExercise(
    val name: String,
    val description: String = "",
    val difficulty: Int = 1,
    val category: String = "strength",
    val equipment: String = "bodyweight",
    val notes: String? = null,
    @SerialName("calories_per_kg_per_hour") val caloriesPerKgPerHour: Double = 3.0,
    @SerialName("primary_muscle") val primaryMuscle: String = "",
    @SerialName("secondary_muscles") val secondaryMuscles: List<String> = emptyList(),
    @SerialName("typical_sets_reps") val typicalSetsReps: String = "3x12",
    @SerialName("execution_tips") val executionTips: List<String> = emptyList(),
    @SerialName("video_url") val videoUrl: String = "",

    // Pre-parsed execution parameters
    val parsedSets: Int = 3,
    val parsedReps: Int = 12,
    val repsDisplay: String = "12", // Original string preserving dashes, e.g., "10-12"
    val recommendedRestSeconds: Int = 60,

    val muscleIntensities: Map<String, MuscleIntensity> = emptyMap()
)

@Serializable
data class MuscleIntensity(
    val muscleName: String,
    val role: MuscleRole, // P, S, T
    val level: Int // 1-10
)

@Serializable
enum class MuscleRole {
    PRIMARY, SECONDARY, TERTIARY, NONE
}

package com.example.myapplication.data
/** * Tip aktivnosti — vpliva na prikaz statistik in izračun kalorij. * MET vrednosti (Metabolic Equivalent of Task) iz standardnih tabel. */ enum class ActivityType( val label: String, val emoji: String, val metValue: Double, // osnova pri zmerni intenzivnosti val showElevation: Boolean, // prikaži vzpon/spust val showPace: Boolean, // prikaži tempo (min/km) val showSpeed: Boolean, // prikaži hitrost (km/h) val unitLabel: String // "km", "km" ali "m" za smučanje ) { RUN( "Run", "", 8.0, true, true, true, "km"), WALK( "Walk", "", 3.5, false, true, true, "km"), HIKE( "Hike", "", 5.3, true, false, true, "km"), SPRINT( "Sprint", "⚡", 14.0, false, true, true, "km"), CYCLING( "Cycling", "", 6.8, true, false, true, "km"), SKIING( "Skiing", "⛷️", 7.0, true, false, true, "km"), SNOWBOARD( "Snowboard", "", 5.5, true, false, true, "km"), SKATING( "Skating", "⛸️", 7.5, false, false, true, "km"), NORDIC( "Nordic Walk","", 4.8, true, true, true, "km");
companion object { fun fromString(s: String?): ActivityType = entries.firstOrNull { it.name.equals(s, ignoreCase = true) } ?: RUN } }
/** * Data class for a single GPS location point during a run. */ data class LocationPoint( val latitude: Double = 0.0, val longitude: Double = 0.0, val altitude: Double = 0.0, val speed: Float = 0.0f, val accuracy: Float = 0.0f, val timestamp: Long = 0L )
/** * Data class for a complete run/activity session. */ data class RunSession( val id: String = "", val userId: String = "", val startTime: Long = 0L, val endTime: Long = 0L, val durationSeconds: Int = 0, val distanceMeters: Double = 0.0, val maxSpeedMps: Float = 0.0f, val avgSpeedMps: Float = 0.0f, val polylinePoints: List<LocationPoint> = emptyList(), val createdAt: Long = System.currentTimeMillis(), val caloriesKcal: Int = 0, val elevationGainM: Float = 0f, val elevationLossM: Float = 0f, val activityType: ActivityType = ActivityType.RUN, val isSmoothed: Boolean = false ) { /** * Calculate average speed from distance and duration. */ fun calculateAvgSpeed(): Float { return if (durationSeconds > 0) { (distanceMeters / durationSeconds).toFloat() } else { 0.0f } }
/** * Convert speed from m/s to km/h. */ fun speedMpsToKmh(mps: Float): Float = mps * 3.6f
/** * Convert speed from m/s to km/h for max and avg. */ fun getMaxSpeedKmh(): Float = speedMpsToKmh(maxSpeedMps) fun getAvgSpeedKmh(): Float = speedMpsToKmh(avgSpeedMps)
/** * Get distance in km. */ fun getDistanceKm(): Double = distanceMeters / 1000.0
/** * Get duration formatted as HH:MM:SS. */ fun formatDuration(): String { val hours = durationSeconds / 3600 val minutes = (durationSeconds % 3600) / 60 val secs = durationSeconds % 60 return String.format("%02d:%02d:%02d", hours, minutes, secs) }
/** * Convert to Firestore-compatible map for storage. */ fun toFirestoreMap(): Map<String, Any> = mapOf( "id" to id, "userId" to userId, "startTime" to startTime, "endTime" to endTime, "durationSeconds" to durationSeconds, "distanceMeters" to distanceMeters, "maxSpeedMps" to maxSpeedMps, "avgSpeedMps" to avgSpeedMps, "polylinePoints" to polylinePoints.map { point -> mapOf( "latitude" to point.latitude, "longitude" to point.longitude, "altitude" to point.altitude, "speed" to point.speed, "accuracy" to point.accuracy, "timestamp" to point.timestamp ) }, "createdAt" to createdAt, "caloriesKcal" to caloriesKcal, "elevationGainM" to elevationGainM, "elevationLossM" to elevationLossM, "activityType" to activityType.name, "isSmoothed" to isSmoothed ) }

